import re

def norm_name(n):
    return re.sub(r"\s+", " ", n.casefold().strip())

def blocking_key(rec):
    ap = norm_name(rec["name"]).split()[-1]
    return f"{ap}|{rec['region'].casefold()}"

print(blocking_key({"name": "Ana Quispe", "region": "Lima"}))
print(blocking_key({"name": "Luis Quispe", "region": "Lima"}))

import re

def norm_doc(d):
    return re.sub(r"[^a-z0-9]", "", d.casefold())

def blocking_key(rec):
    ap = rec["name"].casefold().strip().split()[-1]
    return f"{ap}|{rec['region'].casefold()}"

def er_score(a, b):
    if norm_doc(a["doc"]) == norm_doc(b["doc"]) and blocking_key(a) == blocking_key(b):
        return 1.0
    if blocking_key(a) == blocking_key(b):
        return 0.5
    return 0.0

a = {"name": "Ana Quispe", "region": "Lima", "doc": "12.345.678"}
b = {"name": "Ana  Quispe", "region": "Lima", "doc": "12345678"}
print(norm_doc(a["doc"]), norm_doc(b["doc"]))
print(er_score(a, b))

